#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
CI MAXN=1e4+5;
double d[MAXN];
int a[MAXN],n,k;
bool check(double x)
{
    int sum=0;
    for(int i=1;i<=n;++i)
	{
		sum+=a[i]/x;
	}
    return sum>=k;
}
int main(void){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;++i)
    {
    	scanf("%lf",d+i);
		a[i]=int(d[i]*100);
	}
    int l=0,r=1<<30,ans;
    while(l<=r)
	{
        int mid=(l+r)>>1;
        if(check(mid))
		{
			l=mid+1,ans=mid;
		}else r=mid-1;
    }
    printf("%.2lf",ans/100.0);
    return false;
}
